have h1 : {(n, k) | ∃ hk1 : 1 ≤ k, ∃ hkn : k ≤ 2 * n, ∀ c : Row n, c.valid →
    ∃ i, ∀ j₁ j₂ : Fin (2 * n), (j₁ : ℕ) < n → (j₂ : ℕ) < n →
    (Row.operationOneBased hk1 hkn)^[i] c j₁ = (Row.operationOneBased hk1 hkn)^[i] c j₂} = ∅ := by
  ext ⟨n, k⟩
  simp only [Set.mem_setOf_eq, Set.mem_empty_iff_false, iff_false]
  rintro ⟨hk1, hkn, h⟩
  have h2 := h (fun i => if i % 2 = 0 then Coin.A else Coin.B) (by
    simp [Row.valid, Finset.card_filter, Finset.card_range, Finset.card_univ]
    <;> try { native_decide }
    <;> try { omega }
    <;> try { native_decide }
    <;> try { omega }
  )
  rcases h2 with ⟨i, hi⟩
  have h3 := hi 0 1 (by omega) (by omega)
  simp [Row.operationOneBased] at h3
  all_goals
    try { contradiction }
    <;> try { native_decide }
    <;> try { omega }
    <;> try { native_decide }
    <;> try { omega }
rw [h1]
simp
